('RCV-00003', '그린루프어패럴', '가죽/가방/신발 제조업', JSON_ARRAY('리사이클 백팩', '업사이클 토트백', '컴포트 스니커즈'), '서울특별시 성동구 순환로19길 16', '그린루프어패럴는 혼방 섬유를 다단계 선별·세정해 용도별로 분리 가공하며, 혼합 재질 특성을 반영한 공정으로 재활용 효율을 높입니다. 회수 소재는 주로 리사이클 백팩, 업사이클 토트백, 컴포트 스니커즈 생산 공정에 투입되며, 산업군 요구에 맞춘 품질 검수로 납품 안정성을 유지합니다.', 'blended', '박지후', '02-1311-1459', 'local_small', JSON_ARRAY(0.094221, 0.088857, 0.080938, 0.070754, 0.058670, 0.045115, 0.030565, 0.015529, 0.000526, -0.013927, -0.027335, -0.039244, -0.049257, -0.057042, -0.062352, -0.065027, -0.065001, -0.062307, -0.057072, -0.049514, -0.039933, -0.028702, -0.016255, -0.003067, 0.010359, 0.023512, 0.035888, 0.047012, 0.056450, 0.063830, 0.068851, 0.071295, 0.071034, 0.068037, 0.062370, 0.054193, 0.043755, 0.031388, 0.017492, 0.002523, -0.013021, -0.028623, -0.043756, -0.057910, -0.070604, -0.081406, -0.089945, -0.095926, -0.099141, -0.099473, -0.096904, -0.091513, -0.083473, -0.073048, -0.060581, -0.046484, -0.031221, -0.015297, 0.000765, 0.016438, 0.031212, 0.044610, 0.056203, 0.065629, 0.072601, 0.076919, 0.078476, 0.077262, 0.073365, 0.066965, 0.058328, 0.047800, 0.035791, 0.022760, 0.009203, -0.004369, -0.017446, -0.029537, -0.040188, -0.048998, -0.055631, -0.059831, -0.061431, -0.060356, -0.056626, -0.050361, -0.041769, -0.031144, -0.018854, -0.005330, 0.008954, 0.023490, 0.037762, 0.051256, 0.063484, 0.073999, 0.082411, 0.088400, 0.091727, 0.092245, 0.089902, 0.084743, 0.076909, 0.066634, 0.054236, 0.040104, 0.024687, 0.008480, -0.007998, -0.024216, -0.039653, -0.053816, -0.066252, -0.076573, -0.084458, -0.089674, -0.092076, -0.091618, -0.088350, -0.082417, -0.074057, -0.063588, -0.051399, -0.037937, -0.023689, -0.009167, 0.005111, 0.018639, 0.030939, 0.041582, 0.050198, 0.056492, 0.060253, 0.061362, 0.059796, 0.055627, 0.049022, 0.040237, 0.029604, 0.017524, 0.004451, -0.009125, -0.022694, -0.035745, -0.047782, -0.058344, -0.067020, -0.073465, -0.077409, -0.078670, -0.077161, -0.072888, -0.065958, -0.056569, -0.045005, -0.031629, -0.016867, -0.001197, 0.014