('RCV-00008', '미래업사이클링', '섬유 제품 제조업', JSON_ARRAY('순환 폴리에스터 원단', '니트 원사', '흡음 패브릭'), '서울특별시 노원구 순환로34길 41', '미래업사이클링는 합성 단일 소재를 선별한 뒤 세척·분쇄·재중합 공정을 거쳐 재생 원료화하며, 대량 처리와 균일 품질 관리에 강점을 보입니다. 회수 소재는 주로 순환 폴리에스터 원단, 니트 원사, 흡음 패브릭 생산 공정에 투입되며, 산업군 요구에 맞춘 품질 검수로 납품 안정성을 유지합니다.', 'synthetic', '윤서아', '02-1496-1724', 'general', JSON_ARRAY(-0.067669, -0.060296, -0.050542, -0.038707, -0.025169, -0.010365, 0.005220, 0.021073, 0.036666, 0.051482, 0.065023, 0.076836, 0.086523, 0.093759, 0.098298, 0.099987, 0.098769, 0.094684, 0.087868, 0.078551, 0.067044, 0.053734, 0.039065, 0.023528, 0.007639, -0.008075, -0.023096, -0.036934, -0.049140, -0.059326, -0.067175, -0.072454, -0.075020, -0.074827, -0.071924, -0.066459, -0.058664, -0.048857, -0.037424, -0.024807, -0.011490, 0.002021, 0.015213, 0.027589, 0.038677, 0.048055, 0.055364, 0.060316, 0.062710, 0.062437, 0.059482, 0.053928, 0.045952, 0.035818, 0.023868, 0.010512, -0.003789, -0.018536, -0.033213, -0.047301, -0.060300, -0.071743, -0.081214, -0.088366, -0.092925, -0.094707, -0.093623, -0.089679, -0.082980, -0.073724, -0.062197, -0.048761, -0.033846, -0.017927, -0.001519, 0.014851, 0.030656, 0.045389, 0.058582, 0.069819, 0.078751, 0.085111, 0.088718, 0.089487, 0.087431, 0.082659, 0.075373, 0.065860, 0.054482, 0.041665, 0.027882, 0.013635, -0.000559, -0.014189, -0.026765, -0.037839, -0.047019, -0.053981, -0.058483, -0.060371, -0.059586, -0.056166, -0.050244, -0.042043, -0.031869, -0.020100, -0.007173, 0.006435, 0.020216, 0.033657, 0.046254, 0.057530, 0.067052, 0.074447, 0.079417, 0.081743, 0.081302, 0.078064, 0.072098, 0.063567, 0.052725, 0.039906, 0.025514, 0.010008, -0.006109, -0.022317, -0.038086, -0.052901, -0.066280, -0.077785, -0.087044, -0.093759, -0.097718, -0.098801, -0.096988, -0.092354, -0.085069, -0.075395, -0.063670, -0.050304, -0.035757, -0.020529, -0.005141, 0.009887, 0.024046, 0.036864, 0.047918, 0.056849, 0.063374, 0.067298, 0.068517, 0.067025, 0.062913, 0.056363, 0.047644, 0.037103, 0.025152, 0.012249, -0.001110, -0.0