('RCV-00010', '라온리뉴머티리얼', '가죽/가방/신발 제조업', JSON_ARRAY('비건레더 파우치', '업사이클 슬링백', '캐주얼 슈즈'), '서울특별시 마포구 순환로40길 10', '라온리뉴머티리얼는 천연 단일 섬유 중심으로 회수된 소재를 분리·세척해 재가공하며, 셀룰로오스 기반 자원 순환 공정으로 안정적인 품질을 확보합니다. 회수 소재는 주로 비건레더 파우치, 업사이클 슬링백, 캐주얼 슈즈 생산 공정에 투입되며, 산업군 요구에 맞춘 품질 검수로 납품 안정성을 유지합니다.', 'natural-single', '임다은', '02-1570-1830', 'social_enterprise', JSON_ARRAY(0.003352, 0.019730, 0.035545, 0.050289, 0.063490, 0.074728, 0.083651, 0.089986, 0.093547, 0.094244, 0.092083, 0.087169, 0.079699, 0.069956, 0.058300, 0.045155, 0.030993, 0.016317, 0.001647, -0.012502, -0.025636, -0.037302, -0.047098, -0.054693, -0.059836, -0.062363, -0.062207, -0.059395, -0.054051, -0.046389, -0.036708, -0.025378, -0.012830, 0.000461, 0.013993, 0.027254, 0.039738, 0.050968, 0.060509, 0.067983, 0.073085, 0.075594, 0.075376, 0.072397, 0.066716, 0.058491, 0.047968, 0.035473, 0.021406, 0.006222, -0.009582, -0.025487, -0.040967, -0.055505, -0.068619, -0.079871, -0.088884, -0.095357, -0.099075, -0.099914, -0.097847, -0.092947, -0.085381, -0.075405, -0.063355, -0.049640, -0.034718, -0.019092, -0.003281, 0.012188, 0.026806, 0.040093, 0.051620, 0.061022, 0.068007, 0.072373, 0.074007, 0.072895, 0.069119, 0.062854, 0.054363, 0.043987, 0.032132, 0.019255, 0.005850, -0.007575, -0.020508, -0.032460, -0.042973, -0.051646, -0.058140, -0.062197, -0.063645, -0.062406, -0.058498, -0.052036, -0.043226, -0.032359, -0.019803, -0.005985, 0.008618, 0.023499, 0.038138, 0.052021, 0.064655, 0.075589, 0.084426, 0.090841, 0.094589, 0.095516, 0.093563, 0.088769, 0.081268, 0.071288, 0.059142, 0.045214, 0.029950, 0.013842, -0.002592, -0.018822, -0.034325, -0.048607, -0.061212, -0.071747, -0.079888, -0.085395, -0.088117, -0.088002, -0.085094, -0.079532, -0.071547, -0.061451, -0.049630, -0.036524, -0.022617, -0.008420, 0.005553, 0.018795, 0.030829, 0.041225, 0.049611, 0.055691, 0.059249, 0.060165, 0.058411, 0.054058, 0.047268, 0.038295, 0.027468, 0.015188, 0.001906, -0.011886, -0.025679, -0.038958, -0.051228, -0.062022, -0.070926, -0.077