('RCV-00011', '청담리사이클텍', '플라스틱 제조업', JSON_ARRAY('재생 PET 펠릿', '사출 부품 소재', '순환 플라스틱 시트'), '서울특별시 강서구 순환로43길 15', '청담리사이클텍는 합성 단일 소재를 선별한 뒤 세척·분쇄·재중합 공정을 거쳐 재생 원료화하며, 대량 처리와 균일 품질 관리에 강점을 보입니다. 회수 소재는 주로 재생 PET 펠릿, 사출 부품 소재, 순환 플라스틱 시트 생산 공정에 투입되며, 산업군 요구에 맞춘 품질 검수로 납품 안정성을 유지합니다.', 'synthetic', '한유진', '02-1607-1883', 'general', JSON_ARRAY(0.047463, 0.060140, 0.070763, 0.079007, 0.084627, 0.087470, 0.087480, 0.084697, 0.079257, 0.071386, 0.061395, 0.049666, 0.036638, 0.022793, 0.008640, -0.005304, -0.018535, -0.030574, -0.040988, -0.049404, -0.055522, -0.059126, -0.060090, -0.058385, -0.054076, -0.047324, -0.038379, -0.027570, -0.015293, -0.002000, 0.011821, 0.025658, 0.038997, 0.051341, 0.062223, 0.071226, 0.077996, 0.082257, 0.083819, 0.082583, 0.078548, 0.071812, 0.062565, 0.051083, 0.037724, 0.022910, 0.007115, -0.009153, -0.025367, -0.041000, -0.055544, -0.068527, -0.079529, -0.088197, -0.094256, -0.097520, -0.097898, -0.095394, -0.090113, -0.082251, -0.072091, -0.059994, -0.046384, -0.031734, -0.016551, -0.001357, 0.013329, 0.027011, 0.039229, 0.049577, 0.057717, 0.063394, 0.066438, 0.066774, 0.064426, 0.059510, 0.052236, 0.042898, 0.031863, 0.019556, 0.006452, -0.006950, -0.020137, -0.032606, -0.043877, -0.053513, -0.061134, -0.066433, -0.069183, -0.069248, -0.066587, -0.061256, -0.053408, -0.043282, -0.031203, -0.017565, -0.002817, 0.012546, 0.028007, 0.043044, 0.057142, 0.069820, 0.080641, 0.089229, 0.095282, 0.098586, 0.099016, 0.096545, 0.091246, 0.083283, 0.072914, 0.060476, 0.046375, 0.031074, 0.015074, -0.001103, -0.016927, -0.031886, -0.045499, -0.057331, -0.067014, -0.074252, -0.078838, -0.080656, -0.079687, -0.076010, -0.069796, -0.061305, -0.050877, -0.038916, -0.025878, -0.012257, 0.001437, 0.014692, 0.027013, 0.037943, 0.047073, 0.054061, 0.058642, 0.060639, 0.059969, 0.056642, 0.050767, 0.042544, 0.032260, 0.020273, 0.007010, -0.007060, -0.021433, -0.035592, -0.049025, -0.061241, -0.071790, -0.080276, -0.086373, -0.089836, -0.090510, -0.088333, -0.