('RCV-00023', '부산순환소재', '의복 제조업', JSON_ARRAY('워크웨어 자켓', '기능성 티셔츠', '유니폼 팬츠'), '서울특별시 동대문구 순환로79길 34', '부산순환소재는 합성 단일 소재를 선별한 뒤 세척·분쇄·재중합 공정을 거쳐 재생 원료화하며, 대량 처리와 균일 품질 관리에 강점을 보입니다. 회수 소재는 주로 워크웨어 자켓, 기능성 티셔츠, 유니폼 팬츠 생산 공정에 투입되며, 산업군 요구에 맞춘 품질 검수로 납품 안정성을 유지합니다.', 'synthetic', '남태윤', '02-2051-2519', 'general', JSON_ARRAY(0.055905, 0.049601, 0.040990, 0.030371, 0.018116, 0.004659, -0.009524, -0.023925, -0.038027, -0.051319, -0.063317, -0.073577, -0.081715, -0.087416, -0.090450, -0.090676, -0.088050, -0.082623, -0.074547, -0.064059, -0.051485, -0.037218, -0.021711, -0.005462, 0.011009, 0.027170, 0.042503, 0.056516, 0.068763, 0.078857, 0.086488, 0.091425, 0.093534, 0.092774, 0.089203, 0.082976, 0.074335, 0.063606, 0.051182, 0.037515, 0.023096, 0.008437, -0.005942, -0.019536, -0.031871, -0.042518, -0.051112, -0.057364, -0.061069, -0.062112, -0.060477, -0.056244, -0.049585, -0.040760, -0.030107, -0.018030, -0.004986, 0.008533, 0.022017, 0.034955, 0.046855, 0.057259, 0.065760, 0.072018, 0.075770, 0.076840, 0.075148, 0.070708, 0.063632, 0.054124, 0.042476, 0.029054, 0.014289, -0.001340, -0.017322, -0.033130, -0.048242, -0.062156, -0.074411, -0.084598, -0.092380, -0.097499, -0.099786, -0.099169, -0.095673, -0.089419, -0.080622, -0.069583, -0.056675, -0.042336, -0.027049, -0.011327, 0.004305, 0.019327, 0.033244, 0.045602, 0.056003, 0.064120, 0.069707, 0.072610, 0.072767, 0.070214, 0.065085, 0.057602, 0.048069, 0.036865, 0.024423, 0.011222, -0.002234, -0.015433, -0.027873, -0.039079, -0.048623, -0.056133, -0.061314, -0.063951, -0.063923, -0.061201, -0.055856, -0.048051, -0.038040, -0.026156, -0.012800, 0.001573, 0.016466, 0.031364, 0.045747, 0.059108, 0.070975, 0.080923, 0.088590, 0.093694, 0.096034, 0.095506, 0.092102, 0.085912, 0.077120, 0.065999, 0.052901, 0.038244, 0.022501, 0.006178, -0.010196, -0.026095, -0.041008, -0.054460, -0.066025, -0.075345, -0.082140, -0.086216, -0.087473, -0.085909, -0.081619, -0.074791, -0.065701, -0.054699, -0.042201, -0.028675, -0.014618, -0.0