('RCV-00034', '비전순환산업', '자동차 부품 제조업', JSON_ARRAY('시트 보강 섬유', '내장재 흡음 패드', '방진 보강재'), '서울특별시 서초구 순환로35길 7', '비전순환산업는 천연 단일 섬유 중심으로 회수된 소재를 분리·세척해 재가공하며, 셀룰로오스 기반 자원 순환 공정으로 안정적인 품질을 확보합니다. 회수 소재는 주로 시트 보강 섬유, 내장재 흡음 패드, 방진 보강재 생산 공정에 투입되며, 산업군 요구에 맞춘 품질 검수로 납품 안정성을 유지합니다.', 'natural-single', '양유찬', '02-2458-3102', 'social_enterprise', JSON_ARRAY(0.048492, 0.033936, 0.018240, 0.001905, -0.014544, -0.030577, -0.045678, -0.059365, -0.071202, -0.080816, -0.087912, -0.092279, -0.093800, -0.092456, -0.088323, -0.081574, -0.072470, -0.061349, -0.048621, -0.034744, -0.020215, -0.005550, 0.008732, 0.022131, 0.034180, 0.044463, 0.052630, 0.058405, 0.061602, 0.062126, 0.059980, 0.055261, 0.048160, 0.038954, 0.027996, 0.015700, 0.002532, -0.011012, -0.024419, -0.037182, -0.048812, -0.058862, -0.066938, -0.072712, -0.075940, -0.076464, -0.074221, -0.069248, -0.061673, -0.051720, -0.039696, -0.025980, -0.011015, 0.004712, 0.020687, 0.036381, 0.051276, 0.064876, 0.076729, 0.086441, 0.093689, 0.098232, 0.099921, 0.098702, 0.094621, 0.087818, 0.078526, 0.067062, 0.053812, 0.039225, 0.023791, 0.008027, -0.007540, -0.022395, -0.036049, -0.048058, -0.058038, -0.065676, -0.070745, -0.073108, -0.072724, -0.069647, -0.064030, -0.056111, -0.046212, -0.034722, -0.022086, -0.008789, 0.004662, 0.017756, 0.029995, 0.040912, 0.050088, 0.057166, 0.061866, 0.063992, 0.063440, 0.060202, 0.054366, 0.046116, 0.035721, 0.023527, 0.009949, -0.004548, -0.019463, -0.034279, -0.048477, -0.061556, -0.073051, -0.082551, -0.089707, -0.094253, -0.096007, -0.094885, -0.090899, -0.084157, -0.074861, -0.063303, -0.049847, -0.034925, -0.019017, -0.002635, 0.013691, 0.029436, 0.044094, 0.057200, 0.068341, 0.077173, 0.083431, 0.086942, 0.087624, 0.085495, 0.080669, 0.073352, 0.063836, 0.052485, 0.039728, 0.026038, 0.011920, -0.002112, -0.015547, -0.027899, -0.038723, -0.047632, -0.054305, -0.058508, -0.060092, -0.059004, -0.055289, -0.049086, -0.040623, -0.030212, -0.018234, -0.005130, 0.008619, 0.022505, 0.036014,