('RCV-00041', '리폼플러스산업', '자동차 부품 제조업', JSON_ARRAY('도어트림 흡음재', '트렁크 보강재', '헤드라이너 충전재'), '서울특별시 동대문구 순환로56길 1', '리폼플러스산업는 합성 단일 소재를 선별한 뒤 세척·분쇄·재중합 공정을 거쳐 재생 원료화하며, 대량 처리와 균일 품질 관리에 강점을 보입니다. 회수 소재는 주로 도어트림 흡음재, 트렁크 보강재, 헤드라이너 충전재 생산 공정에 투입되며, 산업군 요구에 맞춘 품질 검수로 납품 안정성을 유지합니다.', 'synthetic', '도서연', '02-2717-3473', 'general', JSON_ARRAY(0.067073, 0.077324, 0.085387, 0.090960, 0.093821, 0.093843, 0.090994, 0.085340, 0.077043, 0.066355, 0.053608, 0.039208, 0.023613, 0.007326, -0.009131, -0.025228, -0.040447, -0.054303, -0.066357, -0.076233, -0.083628, -0.088327, -0.090207, -0.089241, -0.085499, -0.079148, -0.070443, -0.059716, -0.047371, -0.033863, -0.019685, -0.005352, 0.008622, 0.021735, 0.033520, 0.043562, 0.051505, 0.057075, 0.060081, 0.060425, 0.058106, 0.053219, 0.045952, 0.036578, 0.025448, 0.012975, -0.000376, -0.014108, -0.027710, -0.040670, -0.052500, -0.062746, -0.071012, -0.076966, -0.080358, -0.081025, -0.078901, -0.074014, -0.066490, -0.056548, -0.044491, -0.030696, -0.015602, 0.000303, 0.016505, 0.032475, 0.047691, 0.061656, 0.073912, 0.084059, 0.091769, 0.096795, 0.098980, 0.098263, 0.094682, 0.088370, 0.079554, 0.068543, 0.055720, 0.041527, 0.026450, 0.011005, -0.004285, -0.018904, -0.032365, -0.044221, -0.054086, -0.061645, -0.066666, -0.069009, -0.068629, -0.065576, -0.059997, -0.052128, -0.042285, -0.030855, -0.018281, -0.005046, 0.008346, 0.021381, 0.033562, 0.044421, 0.053536, 0.060548, 0.065173, 0.067211, 0.066555, 0.063193, 0.057211, 0.048786, 0.038187, 0.025758, 0.011912, -0.002887, -0.018138, -0.033320, -0.047913, -0.061412, -0.073349, -0.083306, -0.090929, -0.095945, -0.098167, -0.097501, -0.093952, -0.087623, -0.078710, -0.067496, -0.054342, -0.039676, -0.023972, -0.007743, 0.008485, 0.024185, 0.038852, 0.052017, 0.063265, 0.072247, 0.078694, 0.082427, 0.083360, 0.081504, 0.076967, 0.069949, 0.060737, 0.049691, 0.037234, 0.023836, 0.010000, -0.003762, -0.016940, -0.029048, -0.039641, -0.048329, -0.054791, -0.058788, -0.060168, -0.058878, -0.054