('RCV-00045', '한빛리뉴소재', '가죽/가방/신발 제조업', JSON_ARRAY('리사이클 백팩', '업사이클 토트백', '컴포트 스니커즈'), '서울특별시 은평구 순환로68길 21', '한빛리뉴소재는 혼방 섬유를 다단계 선별·세정해 용도별로 분리 가공하며, 혼합 재질 특성을 반영한 공정으로 재활용 효율을 높입니다. 회수 소재는 주로 리사이클 백팩, 업사이클 토트백, 컴포트 스니커즈 생산 공정에 투입되며, 산업군 요구에 맞춘 품질 검수로 납품 안정성을 유지합니다.', 'blended', '길현준', '02-2865-3685', 'local_small', JSON_ARRAY(0.017317, 0.002668, -0.011497, -0.024682, -0.036430, -0.046336, -0.054062, -0.059353, -0.062038, -0.062043, -0.059388, -0.054191, -0.046660, -0.037087, -0.025839, -0.013342, -0.000068, 0.013480, 0.026791, 0.039359, 0.050704, 0.060385, 0.068022, 0.073304, 0.076002, 0.075978, 0.073188, 0.067687, 0.059624, 0.049238, 0.036853, 0.022863, 0.007718, -0.008087, -0.024032, -0.039591, -0.054248, -0.067515, -0.078951, -0.088174, -0.094878, -0.098839, -0.099927, -0.098109, -0.093449, -0.086106, -0.076332, -0.064458, -0.050884, -0.036068, -0.020509, -0.004726, 0.010755, 0.025423, 0.038796, 0.050440, 0.059986, 0.067136, 0.071680, 0.073500, 0.072576, 0.068980, 0.062883, 0.054542, 0.044291, 0.032533, 0.019721, 0.006347, -0.007080, -0.020050, -0.032070, -0.042681, -0.051475, -0.058111, -0.062324, -0.063935, -0.062859, -0.059108, -0.052790, -0.044106, -0.033340, -0.020854, -0.007074, 0.007528, 0.022445, 0.037158, 0.051151, 0.063929, 0.075037, 0.084074, 0.090709, 0.094690, 0.095856, 0.094141, 0.089577, 0.082291, 0.072505, 0.060524, 0.046729, 0.031562, 0.015510, -0.000908, -0.017164, -0.032733, -0.047118, -0.059861, -0.070563, -0.078895, -0.084609, -0.087550, -0.087657, -0.084967, -0.079612, -0.071817, -0.061889, -0.050207, -0.037208, -0.023375, -0.009215, 0.004755, 0.018030, 0.030130, 0.040620, 0.049125, 0.055341, 0.059048, 0.060119, 0.058520, 0.054313, 0.047655, 0.038794, 0.028055, 0.015833, 0.002576, -0.011226, -0.025063, -0.038422, -0.050803, -0.061739, -0.070810, -0.077662, -0.082013, -0.083671, -0.082534, -0.078598, -0.071955, -0.062794, -0.051388, -0.038092, -0.023325, -0.007560, 0.008695, 0.024915, 0.040571, 0.055156, 0.068195, 0.079267, 0.088015, 0.0941